                <h4 className="font-black text-slate-700 text-[12px] leading-relaxed group-hover:text-blue-900 transition-colors uppercase tracking-tight pr-2 pt-0.5 whitespace-normal break-words flex-grow flex items-center">
                  <span className="print-only mr-3 border border-black w-4 h-4 shrink-0" />
                  {doc.name}
                  {doc.badge && <DocBadge type={doc.badge} />}
