        const validityMandatoryCourses = [CourseType.MBA, CourseType.MCA, CourseType.MPharm, CourseType.BPharm];
        const isMandatory = (validityMandatoryCourses.includes(state.courseType!) || state.stream === Stream.Engineering) && state.category !== 'Open';
        docs.push({ name: t.docCasteValidity, badge: isMandatory ? 'mandatory' : 'ifavailable' });
      }
    }
    docs.push({ name: 'Domicile Certificate' });
    return docs;
  }, [isFresh, isProfessional, state.category, state.courseType, state.stream, t]);

  const choiceDocs = useMemo(() => {
