        <div className="space-y-12">
          <header className="border-b-4 border-black pb-8 mb-8">
            <h1 className="text-4xl font-black uppercase tracking-tighter mb-4 text-black">MahaDBT Scholarship Checklist</h1>
            <p className="text-xs font-bold text-slate-600 uppercase tracking-widest mb-8">Pathrikar Campus • Scholarship Assistance Tool Output</p>

            <div className="grid grid-cols-2 gap-y-6 gap-x-12 border-t border-slate-200 pt-6">
              <div className="flex flex-col">
                <span className="text-[10px] uppercase text-slate-500 font-black tracking-widest mb-1">Target Course</span>
                <span className="text-base font-black text-black leading-tight">{state.courseType || state.stream}</span>
              </div>
              <div className="flex flex-col">
                <span className="text-[10px] uppercase text-slate-500 font-black tracking-widest mb-1">Caste Category</span>
                <span className="text-base font-black text-black leading-tight">{state.category}</span>
              </div>
              <div className="flex flex-col">
                <span className="text-[10px] uppercase text-slate-500 font-black tracking-widest mb-1">Academic Year</span>
                <span className="text-base font-black text-black leading-tight">{state.currentYear}{state.currentYear === 1 ? 'st' : state.currentYear === 2 ? 'nd' : state.currentYear === 3 ? 'rd' : 'th'} Year</span>
              </div>
              <div className="flex flex-col">
                <span className="text-[10px] uppercase text-slate-500 font-black tracking-widest mb-1">Application Mode</span>
                <span className="text-base font-black text-black leading-tight">{isFresh ? "FRESH APPLICATION" : "RENEWAL APPLICATION"}</span>
              </div>
            </div>
          </header>

          <div className="space-y-10">
            {declarationForms && (
              <div className="print-section">
                <h3 className="text-xs font-black uppercase tracking-widest text-slate-400 mb-4">Declaration Documents</h3>
                {declarationForms.map((decl, idx) => (
                  <div key={idx} className="print-doc-item">
                    <span className="print-checkbox"></span>
                    <span className="text-sm font-black uppercase">{decl.title}</span>
                  </div>
                ))}
              </div>
            )}

            <div className="print-section">
              <h3 className="text-xs font-black uppercase tracking-widest text-slate-400 mb-4">{t.academicDocs}</h3>
              {academicDocs.map((doc, idx) => (
                <div key={idx} className="print-doc-item">
                  <span className="print-checkbox"></span>
                  <span className="text-sm font-black uppercase">
                    {doc.name}
                    {doc.badge && <DocBadge type={doc.badge} isPrint />}
                  </span>
                </div>
              ))}
            </div>

            <div className="print-section">
              <h3 className="text-xs font-black uppercase tracking-widest text-slate-400 mb-4">{t.categoryDocs}</h3>
              {govtDocs.map((doc, idx) => (
                <div key={idx} className="print-doc-item">
                  <span className="print-checkbox"></span>
                  <span className="text-sm font-black uppercase">
                    {doc.name}
                    {doc.badge && <DocBadge type={doc.badge} isPrint />}
                  </span>
                </div>
              ))}
              {choiceDocs && choiceDocs.map((name, idx) => (
                <div key={idx} className="print-doc-item">
                  <span className="print-checkbox"></span>
                  <span className="text-sm font-black uppercase">
                    {name}
                    <DocBadge type="anyone" isPrint />
                  </span>
                </div>
              ))}
            </div>
          </div>

          <footer className="mt-12 pt-8 border-t border-black text-center">
            <p className="text-sm font-black uppercase tracking-widest text-black mb-2">For guidance only. Final verification will be done at the college office.</p>
            <p className="text-[9px] text-slate-500 uppercase tracking-tighter">Generated on {new Date().toLocaleDateString()} via Assistance Tool</p>
          </footer>
        </div>,
        printArea
      )}

      {/* Main Screen UI */}
      <header className="space-y-4 no-print">
        <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-4">
          <h2 className="text-2xl font-black text-slate-900 tracking-tight leading-tight uppercase max-w-sm">{t.docsTitle}</h2>
          <div className="flex flex-col items-start sm:items-end shrink-0">
            <button 
              onClick={handlePrint}
              className="inline-flex items-center space-x-2 px-3 py-1.5 bg-slate-50 hover:bg-slate-100 active:bg-slate-200 text-slate-600 rounded-full transition-all border border-slate-200/60 shadow-sm"
            >
              <svg className="w-3.5 h-3.5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
