              </div>
              <div className="flex flex-col">
                <span className="text-[10px] uppercase text-slate-500 font-black tracking-widest mb-1">Academic Year</span>
                <span className="text-base font-black text-black leading-tight">{state.currentYear}{state.currentYear === 1 ? 'st' : state.currentYear === 2 ? 'nd' : state.currentYear === 3 ? 'rd' : 'th'} Year</span>
              </div>
              <div className="flex flex-col">
                <span className="text-[10px] uppercase text-slate-500 font-black tracking-widest mb-1">Application Mode</span>
                <span className="text-base font-black text-black leading-tight">{isFresh ? "FRESH APPLICATION" : "RENEWAL APPLICATION"}</span>
              </div>
            </div>
          </header>

          <div className="space-y-10">
            {declarationForms && (
              <div className="print-section">
                <h3 className="text-xs font-black uppercase tracking-widest text-slate-400 mb-4">Declaration Documents</h3>
                {declarationForms.map((decl, idx) => (
                  <div key={idx} className="print-doc-item">
                    <span className="print-checkbox"></span>
                    <span className="text-sm font-black uppercase">{decl.title}</span>
                  </div>
                ))}
              </div>
            )}

            <div className="print-section">
              <h3 className="text-xs font-black uppercase tracking-widest text-slate-400 mb-4">{t.academicDocs}</h3>
              {academicDocs.map((doc, idx) => (
                <div key={idx} className="print-doc-item">
                  <span className="print-checkbox"></span>
                  <span className="text-sm font-black uppercase">
                    {doc.name}
                    {doc.badge && <DocBadge type={doc.badge} isPrint />}
                  </span>
                </div>
              ))}
            </div>

            <div className="print-section">
              <h3 className="text-xs font-black uppercase tracking-widest text-slate-400 mb-4">{t.categoryDocs}</h3>
              {govtDocs.map((doc, idx) => (
