            </div>
          </div>

          <footer className="mt-12 pt-8 border-t border-black text-center">
            <p className="text-sm font-black uppercase tracking-widest text-black mb-2">For guidance only. Final verification will be done at the college office.</p>
            <p className="text-[9px] text-slate-500 uppercase tracking-tighter">Generated on {new Date().toLocaleDateString()} via Assistance Tool</p>
          </footer>
        </div>,
        printArea
      )}

      {/* Main Screen UI */}
