import React, { useState, useMemo, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { Stream, CourseType, Category, AppState, Language } from './types';
import { StreamIcons } from './constants';
import { translations } from './translations';
import * as PDFLib from 'pdf-lib';

// Dynamic import for pdfjs to avoid global issues
const PDFJS_CDN = "https://cdn.jsdelivr.net/npm/pdfjs-dist@4.4.168/build/pdf.min.mjs";

const PERSISTENCE_KEY = 'mahadbt_assist_state_v4';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(PERSISTENCE_KEY);
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch (e) {
        console.error('Failed to parse saved state', e);
      }
    }
    return {
      language: 'en',
      step: 1,
      stream: null,
      courseType: null,
      category: null,
      currentYear: null,
      isHosteller: false,
      hadGap: false,
      loginReady: { username: false, password: false, mobile: false },
    };
  });

  const [activeTool, setActiveTool] = useState<'main' | 'compress' | 'merge' | 'img2pdf'>('main');

  useEffect(() => {
    localStorage.setItem(PERSISTENCE_KEY, JSON.stringify(state));
  }, [state]);

  useEffect(() => {
    document.documentElement.lang = state.language;
  }, [state.language]);

  const [activeVideo, setActiveVideo] = useState<{ title: string; desc: string; url?: string } | null>(null);

  const t = translations[state.language];
  const isRenewal = useMemo(() => state.currentYear !== null && state.currentYear > 1, [state.currentYear]);

  const handleStreamSelect = (s: Stream) => {
    const nextStepNum = (s === Stream.Pharmacy || s === Stream.Management || s === Stream.ASC) ? 2 : 3;
    setState(prev => ({ 
      ...prev, 
      stream: s, 
      courseType: null, 
      currentYear: null, 
      category: null,
      step: nextStepNum
    }));
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleCourseSelect = (c: CourseType) => {
    setState(prev => ({ 
      ...prev, 
      courseType: c, 
      currentYear: null, 
      category: null,
      step: 3
    }));
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleCategorySelect = (cat: Category) => {
    setState(prev => ({ 
      ...prev, 
      category: cat, 
      isHosteller: false,
      step: 4
    }));
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const nextStep = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    if (state.step === 4) {
      if (isRenewal) setState(prev => ({ ...prev, step: 5 }));
      else setState(prev => ({ ...prev, step: 6 }));
      return;
    }
    setState(prev => ({ ...prev, step: Math.min(6, prev.step + 1) }));
  };

  const prevStep = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    if (state.step === 3 && (state.stream !== Stream.Pharmacy && state.stream !== Stream.Management && state.stream !== Stream.ASC)) {
      setState(prev => ({ ...prev, step: 1 }));
      return;
    }
    if (state.step === 6 && !isRenewal) {
      setState(prev => ({ ...prev, step: 4 }));
      return;
    }
    setState(prev => ({ ...prev, step: Math.max(1, prev.step - 1) }));
  };

  const handleRestart = () => {
    // Fixed: 'boolean' was used as a value here. Replaced with 'false' to initialize AppState correctly.
    const newState: AppState = {
      language: state.language,
      step: 1,
      stream: null,
      courseType: null,
      category: null,
      currentYear: null,
      isHosteller: false,
      hadGap: false,
      loginReady: { username: false, password: false, mobile: false },
    };
    setState(newState);
    localStorage.removeItem(PERSISTENCE_KEY);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] text-slate-900 flex flex-col selection:bg-blue-100">
      {/* Video Overlay */}
      {activeVideo && (
        <div className="fixed inset-0 z-[100] bg-slate-900/80 backdrop-blur-md flex items-center justify-center p-6 no-print video-overlay" onClick={() => setActiveVideo(null)}>
          <div className="bg-white w-full max-w-sm rounded-3xl overflow-hidden shadow-2xl relative border border-slate-200" onClick={e => e.stopPropagation()}>
            <button onClick={() => setActiveVideo(null)} className="absolute top-4 right-4 z-10 bg-slate-100 p-2 rounded-full hover:bg-slate-200 transition-colors">
              <svg className="w-5 h-5 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
            <div className="aspect-[9/16] bg-slate-900 flex flex-col items-center justify-center p-10 text-center text-white">
              <h3 className="text-xl font-black mb-4 tracking-tight">{activeVideo.title}</h3>
              <p className="text-sm opacity-60 mb-8 italic">{activeVideo.desc}</p>
              {activeVideo.url && (
                <a href={activeVideo.url} target="_blank" rel="noopener noreferrer" className="bg-white text-blue-900 px-8 py-3.5 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-blue-50 transition-colors">Open Tutorial</a>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-[#1e3a8a] text-white pt-10 pb-12 px-6 sticky top-0 z-40 pt-safe no-select shadow-xl rounded-b-[2rem] no-print">
        <div className="max-w-2xl mx-auto flex flex-col">
          <div className="flex items-center justify-between mb-8">
            <div className="flex flex-col">
              <h1 className="font-black text-2xl tracking-tighter leading-none uppercase">Pathrikar Campus</h1>
              <p className="text-[10px] font-bold text-blue-200/60 uppercase tracking-widest mt-2">{t.subtitle}</p>
            </div>
            <div className="flex bg-blue-900/50 p-1.5 rounded-2xl backdrop-blur-md border border-white/10">
              {(['en', 'hi', 'mr'] as Language[]).map(lang => (
                <button 
                  key={lang} 
                  onClick={() => setState(prev => ({ ...prev, language: lang }))} 
                  className={`px-3 py-1.5 text-[10px] font-black rounded-xl transition-all duration-300 ${state.language === lang ? 'bg-white text-blue-900 shadow-lg' : 'text-blue-200/50 hover:text-white'}`}
                >
                  {lang === 'en' ? 'EN' : lang === 'hi' ? 'हिं' : 'मराठी'}
                </button>
              ))}
            </div>
          </div>

          <div className="flex flex-col items-end space-y-2">
            <span className="text-[9px] font-black text-white uppercase tracking-widest">{t.step} {state.step} {t.of} 6</span>
            <div className="flex w-full space-x-2">
              {[1, 2, 3, 4, 5, 6].map(i => (
                <div key={i} className={`h-[3px] flex-grow rounded-full transition-all duration-500 ${state.step >= i ? 'bg-white shadow-[0_0_8px_rgba(255,255,255,0.5)]' : 'bg-blue-400/30'}`} />
              ))}
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-2xl mx-auto relative z-30 flex-grow w-full -mt-6 px-0 sm:px-4">
        <div className="bg-white min-h-[500px] p-6 pt-8 rounded-t-[2.5rem] sm:rounded-3xl border-x border-t border-slate-100 overflow-hidden pb-12 shadow-[0_-10px_20px_rgba(0,0,0,0.02)] step-container">
          {activeTool !== 'main' && (
             <button onClick={() => setActiveTool('main')} className="mb-8 flex items-center space-x-2 text-slate-400 hover:text-blue-600 font-bold text-[10px] uppercase tracking-widest transition-all group no-print">
               <div className="p-2.5 bg-slate-50 rounded-xl group-hover:bg-blue-50 transition-colors">
                 <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 19l-7-7 7-7" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round" /></svg>
               </div>
               <span className="group-hover:translate-x-0.5 transition-transform">{t.back}</span>
             </button>
          )}

          {activeTool === 'main' && state.step > 1 && (
            <button onClick={prevStep} className="mb-8 flex items-center space-x-2 text-slate-400 hover:text-blue-600 font-bold text-[10px] uppercase tracking-widest transition-all touch-manipulation group no-print">
              <div className="p-2.5 bg-slate-50 rounded-xl group-hover:bg-blue-50 transition-colors">
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 19l-7-7 7-7" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round" /></svg>
              </div>
              <span className="group-hover:translate-x-0.5 transition-transform">{t.back}</span>
            </button>
          )}

          <div className="step-enter">
            {activeTool === 'main' ? (
              <>
                {state.step === 1 && <StepStream selected={state.stream} onSelect={handleStreamSelect} t={t} />}
                {state.step === 2 && <StepCourse selected={state.courseType} stream={state.stream} onSelect={handleCourseSelect} t={t} />}
                {state.step === 3 && <StepCategory selected={state.category} onSelect={handleCategorySelect} t={t} />}
                {state.step === 4 && <StepYear state={state} onUpdate={updates => setState(prev => ({ ...prev, ...updates }))} onContinue={nextStep} t={t} />}
                {state.step === 5 && <StepLoginCheck ready={state.loginReady} onToggle={field => setState(prev => ({ ...prev, loginReady: { ...prev.loginReady, [field]: !prev.loginReady[field] } }))} onContinue={nextStep} t={t} />}
                {state.step === 6 && <StepDocumentList state={state} onRestart={handleRestart} onBack={prevStep} onOpenVideo={(title, desc, url) => setActiveVideo({ title, desc, url })} onOpenTool={(tool) => setActiveTool(tool)} t={t} />}
              </>
            ) : (
              activeTool === 'compress' ? <PDFCompressor t={t} /> : <div>Not Implemented</div>
            )}
          </div>
        </div>
      </main>

      <footer className="w-full py-10 flex flex-col items-center bg-transparent pb-safe no-select no-print">
        <p className="text-slate-400 text-[10px] font-bold uppercase tracking-[0.3em] mb-3 opacity-50">{t.footerText}</p>
        <a href="https://www.instagram.com/sohellsd/" target="_blank" rel="noopener noreferrer" className="text-blue-800 font-black text-xs tracking-tight uppercase hover:text-blue-600 transition-colors">Sohel Sayyad</a>
      </footer>
    </div>
  );
};

/**
 * Advanced Client-Side PDF Compressor
 * Follows strict optimization strategy:
 * 1. Global Optimizations
 * 2. Iterative Page DPI scaling (300 -> 96)
 * 3. Iterative Page re-encoding (80% -> 40%)
 * 4. Adaptive multi-page logic
 */
const PDFCompressor: React.FC<{ t: any }> = ({ t }) => {
  const [file, setFile] = useState<File | null>(null);
  const [status, setStatus] = useState<'idle' | 'processing' | 'success' | 'fail'>('idle');
  const [progress, setProgress] = useState({ step: '', percent: 0 });
  const [finalSize, setFinalSize] = useState<string>('');
  const [compressedData, setCompressedData] = useState<Uint8Array | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (f && f.type === 'application/pdf') {
      setFile(f);
      setStatus('idle');
    }
  };

  const compressPDF = async () => {
    if (!file) return;
    setStatus('processing');
    setProgress({ step: t.stepGlobal, percent: 10 });

    try {
      const pdfjs = await import(PDFJS_CDN);
      pdfjs.GlobalWorkerOptions.workerSrc = `https://cdn.jsdelivr.net/npm/pdfjs-dist@${pdfjs.version}/build/pdf.worker.min.mjs`;

      const arrayBuffer = await file.arrayBuffer();
      const pdfDoc = await PDFLib.PDFDocument.load(arrayBuffer);

      // Pass 1: Global Optimizations
      pdfDoc.setTitle('');
      pdfDoc.setAuthor('');
      pdfDoc.setSubject('');
      pdfDoc.setCreator('');
      pdfDoc.setProducer('');

      const globalOptimized = await pdfDoc.save();
      if (globalOptimized.length <= 230 * 1024) {
        finishSuccess(globalOptimized);
        return;
      }

      const dpiLevels = [300, 200, 150, 120, 96];
      const qualityLevels = [0.8, 0.7, 0.6, 0.5, 0.4];

      let finalBytes = globalOptimized;
      let currentDPIIndex = 0;
      let currentQualityIndex = 0;
      const totalPages = pdfDoc.getPageCount();

      const loadingTask = pdfjs.getDocument({ data: arrayBuffer });
      const doc = await loadingTask.promise;

      while (finalBytes.length > 230 * 1024 && currentDPIIndex < dpiLevels.length) {
        const targetDPI = dpiLevels[currentDPIIndex];
        const targetQuality = qualityLevels[currentQualityIndex];

        setProgress({ 
          step: `${t.stepDPI} ${targetDPI} DPI / Q: ${Math.round(targetQuality * 100)}%`, 
          percent: 30 + (currentDPIIndex * 10) 
        });

        const newPdf = await PDFLib.PDFDocument.create();

        for (let i = 1; i <= totalPages; i++) {
          const page = await doc.getPage(i);
          const viewport = page.getViewport({ scale: targetDPI / 72 });

          const canvas = document.createElement('canvas');
          const context = canvas.getContext('2d')!;
          canvas.width = viewport.width;
          canvas.height = viewport.height;

          await page.render({ canvasContext: context, viewport }).promise;

          const imgData = canvas.toDataURL('image/jpeg', targetQuality);
          const pdfImage = await newPdf.embedJpg(imgData);
          const newPage = newPdf.addPage([viewport.width, viewport.height]);
          newPage.drawImage(pdfImage, {
            x: 0,
            y: 0,
            width: viewport.width,
            height: viewport.height,
          });
        }

        finalBytes = await newPdf.save();

        if (finalBytes.length <= 230 * 1024) {
          finishSuccess(finalBytes);
          return;
        }

        currentQualityIndex++;
        if (currentQualityIndex >= qualityLevels.length) {
          currentQualityIndex = 0;
          currentDPIIndex++;
        }
      }

      setStatus('fail');
    } catch (err) {
      console.error(err);
      setStatus('fail');
    }
  };

  const finishSuccess = (bytes: Uint8Array) => {
    setCompressedData(bytes);
    setFinalSize(`${Math.round(bytes.length / 1024)} KB`);
    setStatus('success');
  };

  const downloadFile = () => {
    if (!compressedData) return;
    const blob = new Blob([compressedData], { type: 'application/pdf' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `Compressed_${file?.name || 'document.pdf'}`;
    a.click();
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <header className="space-y-2">
        <h2 className="text-2xl font-black text-slate-900 tracking-tight leading-tight">{t.compressorTitle}</h2>
        <p className="text-slate-500 font-medium text-sm leading-relaxed">{t.disclaimer}</p>
      </header>

      <div className="space-y-4">
        {status === 'idle' && (
          <div 
            onClick={() => fileInputRef.current?.click()}
            className="border-2 border-dashed border-slate-200 bg-slate-50/50 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-300 transition-all active:scale-[0.98]"
          >
            <input type="file" ref={fileInputRef} onChange={handleFileSelect} accept=".pdf" className="hidden" />
            <div className="bg-white w-14 h-14 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-center mx-auto mb-4 text-slate-400">
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" /></svg>
            </div>
            <p className="font-black text-sm text-slate-800 uppercase tracking-widest">{file ? file.name : t.selectFile}</p>
            {file && <p className="text-[10px] text-slate-400 mt-2 font-bold uppercase">{Math.round(file.size / 1024)} KB Original</p>}
          </div>
        )}

        {status === 'processing' && (
          <div className="bg-slate-50 border border-slate-100 rounded-3xl p-8 text-center space-y-6">
            <div className="w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-4" />
            <div className="space-y-2">
              <p className="font-black text-xs uppercase tracking-widest text-blue-900">{t.compressing}</p>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tight">{progress.step}</p>
            </div>
            <div className="w-full bg-slate-200 h-1 rounded-full overflow-hidden">
              <div className="bg-blue-600 h-full transition-all duration-500" style={{ width: `${progress.percent}%` }} />
            </div>
          </div>
        )}

        {status === 'success' && (
          <div className="bg-emerald-50 border border-emerald-100 rounded-3xl p-8 text-center space-y-6">
            <div className="bg-white w-14 h-14 rounded-full shadow-lg shadow-emerald-200 border border-emerald-100 flex items-center justify-center mx-auto text-emerald-600">
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>
            </div>
            <div className="space-y-1">
              <p className="font-black text-xs uppercase tracking-widest text-emerald-900">{t.successSize}</p>
              <p className="text-2xl font-black text-emerald-600">{finalSize}</p>
            </div>
