/**
 * Shared Success UI with mandatory Rename-before-Download
 */
const SuccessUI: React.FC<{ bytes: Uint8Array, t: any, onRestart: () => void }> = ({ bytes, t, onRestart }) => {
  const [newName, setNewName] = useState('');
  const sizeKB = Math.round(bytes.length / 1024);

  const suggestions = [
    { label: 'Income_Certificate', val: 'Income_Certificate' },
    { label: 'Marksheet', val: 'Marksheet' },
    { label: 'Aadhaar_Card', val: 'Aadhaar_Card' },
    { label: 'Declaration', val: 'Declaration' },
  ];

  const downloadFile = () => {
    if (!newName.trim()) return;
    const blob = new Blob([bytes], { type: 'application/pdf' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    const cleanName = newName.trim().replace(/\.pdf$/i, '');
    a.download = `${cleanName}.pdf`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="bg-emerald-50 border border-emerald-100 rounded-3xl p-8 text-center space-y-6">
      <div className="bg-white w-14 h-14 rounded-full shadow-lg shadow-emerald-200 border border-emerald-100 flex items-center justify-center mx-auto text-emerald-600">
         <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>
      </div>
      <div className="space-y-1">
        <p className="font-black text-xs uppercase tracking-widest text-emerald-900">{t.successSize}</p>
        <p className="text-2xl font-black text-emerald-600">{sizeKB} KB</p>
      </div>

      <div className="space-y-3 text-left">
        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t.renameLabel}</label>
        <input 
          type="text" 
          value={newName} 
          onChange={(e) => setNewName(e.target.value)}
          placeholder={t.renamePlaceholder}
          className="w-full bg-white border border-emerald-100 rounded-2xl px-5 py-4 text-sm font-bold text-slate-800 focus:outline-none focus:ring-2 focus:ring-emerald-200 transition-all shadow-sm"
        />
        <div className="flex flex-wrap gap-2">
           {suggestions.map(s => (
             <button key={s.val} onClick={() => setNewName(s.val)} className="px-2 py-1 bg-white border border-emerald-100 rounded-md text-[8px] font-black text-emerald-600 uppercase hover:bg-emerald-100 transition-colors">
               {s.label}
             </button>
           ))}
        </div>
      </div>

      <button onClick={downloadFile} disabled={!newName.trim()} className="w-full bg-emerald-600 text-white font-black py-4 rounded-2xl shadow-lg active:scale-[0.98] uppercase tracking-[0.2em] text-[10px] disabled:opacity-30 disabled:grayscale transition-all">
        {t.downloadFile}
      </button>
      <button onClick={onRestart} className="text-[10px] font-black text-emerald-600/60 uppercase tracking-widest hover:text-emerald-700">{t.restart}</button>
    </div>
  );
};

/**
 * Smart PDF Compressor
 */
const PDFCompressor: React.FC<{ t: any }> = ({ t }) => {
  const [file, setFile] = useState<File | null>(null);
  const [status, setStatus] = useState<'idle' | 'processing' | 'success' | 'fail'>('idle');
  const [result, setResult] = useState<Uint8Array | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleCompress = async () => {
    if (!file) return;
    setStatus('processing');
    const bytes = await file.arrayBuffer();
    const compressed = await compressPDFBytes(bytes, t);
    if (compressed) {
      setResult(compressed);
      setStatus('success');
    } else {
      setStatus('fail');
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
      <header className="space-y-2 text-left">
        <h2 className="text-2xl font-black text-slate-900 tracking-tight leading-tight uppercase">{t.compressorTitle}</h2>
        <p className="text-slate-500 font-medium text-sm leading-relaxed">{t.disclaimer}</p>
      </header>
      {status === 'idle' && (
        <div onClick={() => fileInputRef.current?.click()} className="border-2 border-dashed border-slate-200 bg-slate-50/50 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-300">
          <input type="file" ref={fileInputRef} onChange={(e) => setFile(e.target.files?.[0] || null)} accept=".pdf" className="hidden" />
          <p className="font-black text-sm text-slate-800 uppercase tracking-widest">{file ? file.name : t.selectFile}</p>
          {file && <button onClick={(e) => { e.stopPropagation(); handleCompress(); }} className="mt-6 w-full bg-blue-900 text-white font-black py-4 rounded-2xl uppercase tracking-widest text-[10px]">{t.continue}</button>}
        </div>
      )}
      {status === 'processing' && <div className="p-10 text-center"><div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-4" /><p className="font-black text-xs uppercase text-slate-400">{t.compressing}</p></div>}
      {status === 'success' && result && <SuccessUI bytes={result} t={t} onRestart={() => setStatus('idle')} />}
      {status === 'fail' && <div className="p-8 bg-slate-50 rounded-3xl text-center"><p className="font-black text-xs uppercase text-slate-800 mb-4">{t.errorMultiPage}</p><button onClick={() => setStatus('idle')} className="w-full bg-slate-100 text-slate-500 font-black py-4 rounded-2xl uppercase tracking-widest text-[10px]">{t.restart}</button></div>}
    </div>
  );
};

/**
 * Merge PDF documents
 */
const PDFMerger: React.FC<{ t: any }> = ({ t }) => {
  const [files, setFiles] = useState<File[]>([]);
  const [status, setStatus] = useState<'idle' | 'processing' | 'success' | 'fail'>('idle');
  const [result, setResult] = useState<Uint8Array | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleMerge = async () => {
    if (files.length < 2) return;
    setStatus('processing');
    try {
      const mergedPdf = await PDFLib.PDFDocument.create();
      for (const f of files) {
        const bytes = await f.arrayBuffer();
        const doc = await PDFLib.PDFDocument.load(bytes);
        const pages = await mergedPdf.copyPages(doc, doc.getPageIndices());
        pages.forEach(p => mergedPdf.addPage(p));
      }
      const mergedBytes = await mergedPdf.save();
      const compressed = await compressPDFBytes(mergedBytes, t);
      if (compressed) {
        setResult(compressed);
        setStatus('success');
      } else {
        setStatus('fail');
      }
    } catch (e) {
      console.error(e);
      setStatus('fail');
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
      <header className="space-y-2 text-left">
        <h2 className="text-2xl font-black text-slate-900 tracking-tight leading-tight uppercase">{t.mergerTitle}</h2>
        <p className="text-slate-500 font-medium text-sm leading-relaxed">{t.disclaimer}</p>
      </header>
      {status === 'idle' && (
        <div className="space-y-4">
          <div onClick={() => fileInputRef.current?.click()} className="border-2 border-dashed border-slate-200 bg-slate-50/50 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-300">
            <input type="file" ref={fileInputRef} onChange={(e) => setFiles(Array.from(e.target.files || []))} multiple accept=".pdf" className="hidden" />
            <p className="font-black text-sm text-slate-800 uppercase tracking-widest">{files.length > 0 ? `${files.length} Files` : t.selectFiles}</p>
          </div>
          {files.length > 1 && <button onClick={handleMerge} className="w-full bg-blue-900 text-white font-black py-5 rounded-2xl uppercase tracking-widest text-[11px] h-16">{t.continue}</button>}
        </div>
      )}
      {status === 'processing' && <div className="p-10 text-center"><div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-4" /><p className="font-black text-xs uppercase text-slate-400">{t.merging}</p></div>}
      {status === 'success' && result && <SuccessUI bytes={result} t={t} onRestart={() => setStatus('idle')} />}
      {status === 'fail' && <div className="p-8 bg-slate-50 rounded-3xl text-center"><p className="font-black text-xs uppercase text-slate-800 mb-4">{t.errorMultiPage}</p><button onClick={() => setStatus('idle')} className="w-full bg-slate-100 text-slate-500 font-black py-4 rounded-2xl uppercase tracking-widest text-[10px]">{t.restart}</button></div>}
    </div>
  );
};

/**
 * Image to PDF Converter
 */
const ImageToPDF: React.FC<{ t: any }> = ({ t }) => {
  const [images, setImages] = useState<File[]>([]);
  const [status, setStatus] = useState<'idle' | 'processing' | 'success' | 'fail'>('idle');
  const [result, setResult] = useState<Uint8Array | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleConvert = async () => {
    if (images.length === 0) return;
    setStatus('processing');
    try {
      const pdfDoc = await PDFLib.PDFDocument.create();
      for (const img of images) {
        const bytes = await img.arrayBuffer();
        let pdfImage;
        if (img.type === 'image/jpeg' || img.type === 'image/jpg') {
          pdfImage = await pdfDoc.embedJpg(bytes);
        } else if (img.type === 'image/png') {
          pdfImage = await pdfDoc.embedPng(bytes);
        } else {
          continue;
        }
        const dims = pdfImage.scale(1);
        const page = pdfDoc.addPage([dims.width, dims.height]);
        page.drawImage(pdfImage, { x: 0, y: 0, width: dims.width, height: dims.height });
      }
      const rawPdf = await pdfDoc.save();
      const compressed = await compressPDFBytes(rawPdf, t);
      if (compressed) {
        setResult(compressed);
        setStatus('success');
      } else {
        setStatus('fail');
      }
    } catch (e) {
      console.error(e);
      setStatus('fail');
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
      <header className="space-y-2 text-left">
        <h2 className="text-2xl font-black text-slate-900 tracking-tight leading-tight uppercase">{t.imgToPdfTitle}</h2>
        <p className="text-slate-500 font-medium text-sm leading-relaxed">{t.disclaimer}</p>
      </header>
      {status === 'idle' && (
        <div className="space-y-4">
          <div onClick={() => fileInputRef.current?.click()} className="border-2 border-dashed border-slate-200 bg-slate-50/50 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-300">
            <input type="file" ref={fileInputRef} onChange={(e) => setImages(Array.from(e.target.files || []))} multiple accept="image/*" className="hidden" />
            <p className="font-black text-sm text-slate-800 uppercase tracking-widest">{images.length > 0 ? `${images.length} Images` : t.selectImages}</p>
          </div>
          {images.length > 0 && <button onClick={handleConvert} className="w-full bg-blue-900 text-white font-black py-5 rounded-2xl uppercase tracking-widest text-[11px] h-16">{t.continue}</button>}
        </div>
      )}
      {status === 'processing' && <div className="p-10 text-center"><div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-4" /><p className="font-black text-xs uppercase text-slate-400">{t.processing}</p></div>}
      {status === 'success' && result && <SuccessUI bytes={result} t={t} onRestart={() => setStatus('idle')} />}
      {status === 'fail' && <div className="p-8 bg-slate-50 rounded-3xl text-center"><p className="font-black text-xs uppercase text-slate-800 mb-4">{t.errorMultiPage}</p><button onClick={() => setStatus('idle')} className="w-full bg-slate-100 text-slate-500 font-black py-4 rounded-2xl uppercase tracking-widest text-[10px]">{t.restart}</button></div>}
    </div>
  );
};

