  const isRenewal = useMemo(() => state.currentYear !== null && state.currentYear > 1, [state.currentYear]);

  const handleStreamSelect = (s: Stream) => {
    const nextStepNum = (s === Stream.Pharmacy || s === Stream.Management || s === Stream.ASC) ? 2 : 3;
    setState(prev => ({ ...prev, stream: s, courseType: null, currentYear: null, category: null, step: nextStepNum }));
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleCourseSelect = (c: CourseType) => {
    setState(prev => ({ ...prev, courseType: c, currentYear: null, category: null, step: 3 }));
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleCategorySelect = (cat: Category) => {
    setState(prev => ({ ...prev, category: cat, isHosteller: false, step: 4 }));
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const nextStep = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    if (state.step === 4) {
      if (isRenewal) setState(prev => ({ ...prev, step: 5 }));
      else setState(prev => ({ ...prev, step: 6 }));
      return;
    }
    setState(prev => ({ ...prev, step: Math.min(6, prev.step + 1) }));
  };

  const prevStep = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    if (state.step === 3 && (state.stream !== Stream.Pharmacy && state.stream !== Stream.Management && state.stream !== Stream.ASC)) {
      setState(prev => ({ ...prev, step: 1 }));
      return;
    }
    if (state.step === 6 && !isRenewal) {
      setState(prev => ({ ...prev, step: 4 }));
      return;
    }
    setState(prev => ({ ...prev, step: Math.max(1, prev.step - 1) }));
  };

  const handleRestart = () => {
    const newState: AppState = {
      language: state.language,
      step: 1,
      stream: null,
      courseType: null,
      category: null,
      currentYear: null,
      isHosteller: false,
      hadGap: false,
      loginReady: { username: false, password: false, mobile: false },
    };
    setState(newState);
    localStorage.removeItem(PERSISTENCE_KEY);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] text-slate-900 flex flex-col selection:bg-blue-100">
      {/* Video Overlay */}
      {activeVideo && (
        <div className="fixed inset-0 z-[100] bg-slate-900/80 backdrop-blur-md flex items-center justify-center p-6 no-print video-overlay" onClick={() => setActiveVideo(null)}>
          <div className="bg-white w-full max-w-sm rounded-3xl overflow-hidden shadow-2xl relative border border-slate-200" onClick={e => e.stopPropagation()}>
            <button onClick={() => setActiveVideo(null)} className="absolute top-4 right-4 z-10 bg-slate-100 p-2 rounded-full hover:bg-slate-200 transition-colors">
              <svg className="w-5 h-5 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
            <div className="aspect-[9/16] bg-slate-900 flex flex-col items-center justify-center p-10 text-center text-white">
              <h3 className="text-xl font-black mb-4 tracking-tight">{activeVideo.title}</h3>
              <p className="text-sm opacity-60 mb-8 italic">{activeVideo.desc}</p>
              {activeVideo.url && (
                <a href={activeVideo.url} target="_blank" rel="noopener noreferrer" className="bg-white text-blue-900 px-8 py-3.5 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-blue-50 transition-colors">Open Tutorial</a>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-[#1e3a8a] text-white pt-10 pb-12 px-6 sticky top-0 z-40 pt-safe no-select shadow-xl rounded-b-[2rem] no-print">
        <div className="max-w-2xl mx-auto flex flex-col">
          <div className="flex items-center justify-between mb-8">
            <div className="flex flex-col text-left">
              <h1 className="font-black text-2xl tracking-tighter leading-none uppercase">Pathrikar Campus</h1>
              <p className="text-[10px] font-bold text-blue-200/60 uppercase tracking-widest mt-2">{t.subtitle}</p>
            </div>
            <div className="flex bg-blue-900/50 p-1.5 rounded-2xl backdrop-blur-md border border-white/10">
              {(['en', 'hi', 'mr'] as Language[]).map(lang => (
                <button key={lang} onClick={() => setState(prev => ({ ...prev, language: lang }))} className={`px-3 py-1.5 text-[10px] font-black rounded-xl transition-all duration-300 ${state.language === lang ? 'bg-white text-blue-900 shadow-lg' : 'text-blue-200/50 hover:text-white'}`}>
                  {lang === 'en' ? 'EN' : lang === 'hi' ? 'हिं' : 'मराठी'}
                </button>
              ))}
            </div>
          </div>
          <div className="flex flex-col items-end space-y-2">
            <span className="text-[9px] font-black text-white uppercase tracking-widest">{t.step} {state.step} {t.of} 6</span>
            <div className="flex w-full space-x-2">
              {[1, 2, 3, 4, 5, 6].map(i => (
                <div key={i} className={`h-[3px] flex-grow rounded-full transition-all duration-500 ${state.step >= i ? 'bg-white shadow-[0_0_8px_rgba(255,255,255,0.5)]' : 'bg-blue-400/30'}`} />
              ))}
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-2xl mx-auto relative z-30 flex-grow w-full -mt-6 px-0 sm:px-4">
        <div className="bg-white min-h-[500px] p-6 pt-8 rounded-t-[2.5rem] sm:rounded-3xl border-x border-t border-slate-100 overflow-hidden pb-12 shadow-[0_-10px_20px_rgba(0,0,0,0.02)] step-container">
          {activeTool !== 'main' && (
             <button onClick={() => setActiveTool('main')} className="mb-8 flex items-center space-x-2 text-slate-400 hover:text-blue-600 font-bold text-[10px] uppercase tracking-widest transition-all group no-print">
               <div className="p-2.5 bg-slate-50 rounded-xl group-hover:bg-blue-50 transition-colors">
                 <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 19l-7-7 7-7" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round" /></svg>
               </div>
               <span className="group-hover:translate-x-0.5 transition-transform">{t.back}</span>
             </button>
          )}

          {activeTool === 'main' && state.step > 1 && (
            <button onClick={prevStep} className="mb-8 flex items-center space-x-2 text-slate-400 hover:text-blue-600 font-bold text-[10px] uppercase tracking-widest transition-all touch-manipulation group no-print">
              <div className="p-2.5 bg-slate-50 rounded-xl group-hover:bg-blue-50 transition-colors">
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 19l-7-7 7-7" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round" /></svg>
              </div>
              <span className="group-hover:translate-x-0.5 transition-transform">{t.back}</span>
            </button>
          )}

          <div className="step-enter">
            {activeTool === 'main' ? (
              <>
                {state.step === 1 && <StepStream selected={state.stream} onSelect={handleStreamSelect} t={t} />}
                {state.step === 2 && <StepCourse selected={state.courseType} stream={state.stream} onSelect={handleCourseSelect} t={t} />}
                {state.step === 3 && <StepCategory selected={state.category} onSelect={handleCategorySelect} t={t} />}
                {state.step === 4 && <StepYear state={state} onUpdate={updates => setState(prev => ({ ...prev, ...updates }))} onContinue={nextStep} t={t} />}
                {state.step === 5 && <StepLoginCheck ready={state.loginReady} onToggle={field => setState(prev => ({ ...prev, loginReady: { ...prev.loginReady, [field]: !prev.loginReady[field] } }))} onContinue={nextStep} t={t} />}
                {state.step === 6 && <StepDocumentList state={state} onRestart={handleRestart} onBack={prevStep} onOpenVideo={(title, desc, url) => setActiveVideo({ title, desc, url })} onOpenTool={(tool) => setActiveTool(tool)} t={t} />}
              </>
            ) : (
              activeTool === 'compress' ? <PDFCompressor t={t} /> : 
              activeTool === 'merge' ? <PDFMerger t={t} /> :
              activeTool === 'img2pdf' ? <ImageToPDF t={t} /> :
              <div>Not Implemented</div>
            )}
          </div>
        </div>
      </main>

      <footer className="w-full py-10 flex flex-col items-center bg-transparent pb-safe no-select no-print">
        <p className="text-slate-400 text-[10px] font-bold uppercase tracking-[0.3em] mb-3 opacity-50">{t.footerText}</p>
        <a href="https://www.instagram.com/sohellsd/" target="_blank" rel="noopener noreferrer" className="text-blue-800 font-black text-xs tracking-tight uppercase hover:text-blue-600 transition-colors">Sohel Sayyad</a>
      </footer>
    </div>
  );
};

/**
 * Shared Success UI with mandatory Rename-before-Download
 */
const SuccessUI: React.FC<{ bytes: Uint8Array, t: any, onRestart: () => void }> = ({ bytes, t, onRestart }) => {
  const [newName, setNewName] = useState('');
  const sizeKB = Math.round(bytes.length / 1024);

  const suggestions = [
    { label: 'Income_Certificate', val: 'Income_Certificate' },
    { label: 'Marksheet', val: 'Marksheet' },
    { label: 'Aadhaar_Card', val: 'Aadhaar_Card' },
    { label: 'Declaration', val: 'Declaration' },
  ];

  const downloadFile = () => {
    if (!newName.trim()) return;
    const blob = new Blob([bytes], { type: 'application/pdf' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    const cleanName = newName.trim().replace(/\.pdf$/i, '');
    a.download = `${cleanName}.pdf`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="bg-emerald-50 border border-emerald-100 rounded-3xl p-8 text-center space-y-6">
      <div className="bg-white w-14 h-14 rounded-full shadow-lg shadow-emerald-200 border border-emerald-100 flex items-center justify-center mx-auto text-emerald-600">
         <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>
      </div>
      <div className="space-y-1">
        <p className="font-black text-xs uppercase tracking-widest text-emerald-900">{t.successSize}</p>
        <p className="text-2xl font-black text-emerald-600">{sizeKB} KB</p>
      </div>

      <div className="space-y-3 text-left">
        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t.renameLabel}</label>
        <input 
          type="text" 
          value={newName} 
          onChange={(e) => setNewName(e.target.value)}
          placeholder={t.renamePlaceholder}
          className="w-full bg-white border border-emerald-100 rounded-2xl px-5 py-4 text-sm font-bold text-slate-800 focus:outline-none focus:ring-2 focus:ring-emerald-200 transition-all shadow-sm"
        />
        <div className="flex flex-wrap gap-2">
           {suggestions.map(s => (
             <button key={s.val} onClick={() => setNewName(s.val)} className="px-2 py-1 bg-white border border-emerald-100 rounded-md text-[8px] font-black text-emerald-600 uppercase hover:bg-emerald-100 transition-colors">
               {s.label}
             </button>
           ))}
        </div>
      </div>

      <button onClick={downloadFile} disabled={!newName.trim()} className="w-full bg-emerald-600 text-white font-black py-4 rounded-2xl shadow-lg active:scale-[0.98] uppercase tracking-[0.2em] text-[10px] disabled:opacity-30 disabled:grayscale transition-all">
        {t.downloadFile}
      </button>
      <button onClick={onRestart} className="text-[10px] font-black text-emerald-600/60 uppercase tracking-widest hover:text-emerald-700">{t.restart}</button>
    </div>
  );
};

/**
 * Smart PDF Compressor
 */
const PDFCompressor: React.FC<{ t: any }> = ({ t }) => {
  const [file, setFile] = useState<File | null>(null);
  const [status, setStatus] = useState<'idle' | 'processing' | 'success' | 'fail'>('idle');
  const [result, setResult] = useState<Uint8Array | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleCompress = async () => {
    if (!file) return;
    setStatus('processing');
    const bytes = await file.arrayBuffer();
    const compressed = await compressPDFBytes(bytes, t);
    if (compressed) {
      setResult(compressed);
      setStatus('success');
    } else {
      setStatus('fail');
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
      <header className="space-y-2 text-left">
        <h2 className="text-2xl font-black text-slate-900 tracking-tight leading-tight uppercase">{t.compressorTitle}</h2>
      </header>
      {status === 'idle' && (
        <div onClick={() => fileInputRef.current?.click()} className="border-2 border-dashed border-slate-200 bg-slate-50/50 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-300">
          <input type="file" ref={fileInputRef} onChange={(e) => setFile(e.target.files?.[0] || null)} accept=".pdf" className="hidden" />
          <p className="font-black text-sm text-slate-800 uppercase tracking-widest">{file ? file.name : t.selectFile}</p>
          {file && <button onClick={(e) => { e.stopPropagation(); handleCompress(); }} className="mt-6 w-full bg-blue-900 text-white font-black py-4 rounded-2xl uppercase tracking-widest text-[10px]">{t.continue}</button>}
        </div>
      )}
      {status === 'processing' && <div className="p-10 text-center"><div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-4" /><p className="font-black text-xs uppercase text-slate-400">{t.compressing}</p></div>}
      {status === 'success' && result && <SuccessUI bytes={result} t={t} onRestart={() => setStatus('idle')} />}
      {status === 'fail' && <div className="p-8 bg-slate-50 rounded-3xl text-center"><p className="text-xs font-black text-slate-800 uppercase leading-relaxed mb-4">{t.errorMultiPage}</p><button onClick={() => setStatus('idle')} className="w-full bg-slate-100 text-slate-500 font-black py-4 rounded-2xl uppercase tracking-widest text-[10px]">{t.restart}</button></div>}
    </div>
  );
};

/**
 * Merge PDF documents
 */
const PDFMerger: React.FC<{ t: any }> = ({ t }) => {
  const [files, setFiles] = useState<File[]>([]);
  const [status, setStatus] = useState<'idle' | 'processing' | 'success' | 'fail'>('idle');
  const [result, setResult] = useState<Uint8Array | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleMerge = async () => {
    if (files.length < 2) return;
    setStatus('processing');
    try {
      const mergedPdf = await PDFLib.PDFDocument.create();
      for (const f of files) {
        const bytes = await f.arrayBuffer();
        const doc = await PDFLib.PDFDocument.load(bytes);
        const pages = await mergedPdf.copyPages(doc, doc.getPageIndices());
        pages.forEach(p => mergedPdf.addPage(p));
      }
      const mergedBytes = await mergedPdf.save();
      const compressed = await compressPDFBytes(mergedBytes, t);
      if (compressed) {
        setResult(compressed);
        setStatus('success');
      } else {
        setStatus('fail');
      }
    } catch (e) {
      console.error(e);
      setStatus('fail');
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
      <header className="space-y-2 text-left">
        <h2 className="text-2xl font-black text-slate-900 tracking-tight leading-tight uppercase">{t.mergerTitle}</h2>
      </header>
      {status === 'idle' && (
        <div className="space-y-4">
          <div onClick={() => fileInputRef.current?.click()} className="border-2 border-dashed border-slate-200 bg-slate-50/50 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-300">
            <input type="file" ref={fileInputRef} onChange={(e) => setFiles(Array.from(e.target.files || []))} multiple accept=".pdf" className="hidden" />
            <p className="font-black text-sm text-slate-800 uppercase tracking-widest">{files.length > 0 ? `${files.length} Files` : t.selectFiles}</p>
          </div>
          {files.length > 1 && <button onClick={handleMerge} className="w-full bg-blue-900 text-white font-black py-5 rounded-2xl uppercase tracking-widest text-[11px] h-16">{t.continue}</button>}
        </div>
      )}
      {status === 'processing' && <div className="p-10 text-center"><div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-4" /><p className="font-black text-xs uppercase text-slate-400">{t.merging}</p></div>}
      {status === 'success' && result && <SuccessUI bytes={result} t={t} onRestart={() => setStatus('idle')} />}
      {status === 'fail' && <div className="p-8 bg-slate-50 rounded-3xl text-center"><p className="text-xs font-black text-slate-800 uppercase leading-relaxed mb-4">{t.errorMultiPage}</p><button onClick={() => setStatus('idle')} className="w-full bg-slate-100 text-slate-500 font-black py-4 rounded-2xl uppercase tracking-widest text-[10px]">{t.restart}</button></div>}
    </div>
  );
};

/**
 * Image to PDF Converter
 */
const ImageToPDF: React.FC<{ t: any }> = ({ t }) => {
  const [images, setImages] = useState<File[]>([]);
  const [status, setStatus] = useState<'idle' | 'processing' | 'success' | 'fail'>('idle');
  const [result, setResult] = useState<Uint8Array | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleConvert = async () => {
    if (images.length === 0) return;
    setStatus('processing');
    try {
      const pdfDoc = await PDFLib.PDFDocument.create();
      for (const img of images) {
        const bytes = await img.arrayBuffer();
        let pdfImage;
        if (img.type === 'image/jpeg' || img.type === 'image/jpg') {
          pdfImage = await pdfDoc.embedJpg(bytes);
        } else if (img.type === 'image/png') {
          pdfImage = await pdfDoc.embedPng(bytes);
        } else {
          continue;
        }
        const dims = pdfImage.scale(1);
        const page = pdfDoc.addPage([dims.width, dims.height]);
        page.drawImage(pdfImage, { x: 0, y: 0, width: dims.width, height: dims.height });
      }
      const rawPdf = await pdfDoc.save();
      const compressed = await compressPDFBytes(rawPdf, t);
      if (compressed) {
        setResult(compressed);
        setStatus('success');
      } else {
        setStatus('fail');
      }
    } catch (e) {
      console.error(e);
      setStatus('fail');
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
      <header className="space-y-2 text-left">
        <h2 className="text-2xl font-black text-slate-900 tracking-tight leading-tight uppercase">{t.imgToPdfTitle}</h2>
      </header>
      {status === 'idle' && (
        <div className="space-y-4">
          <div onClick={() => fileInputRef.current?.click()} className="border-2 border-dashed border-slate-200 bg-slate-50/50 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-300">
            <input type="file" ref={fileInputRef} onChange={(e) => setImages(Array.from(e.target.files || []))} multiple accept="image/*" className="hidden" />
            <p className="font-black text-sm text-slate-800 uppercase tracking-widest">{images.length > 0 ? `${images.length} Images` : t.selectImages}</p>
          </div>
          {images.length > 0 && <button onClick={handleConvert} className="w-full bg-blue-900 text-white font-black py-5 rounded-2xl uppercase tracking-widest text-[11px] h-16">{t.continue}</button>}
        </div>
      )}
      {status === 'processing' && <div className="p-10 text-center"><div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-4" /><p className="font-black text-xs uppercase text-slate-400">{t.processing}</p></div>}
      {status === 'success' && result && <SuccessUI bytes={result} t={t} onRestart={() => setStatus('idle')} />}
      {status === 'fail' && <div className="p-8 bg-slate-50 rounded-3xl text-center"><p className="text-xs font-black text-slate-800 uppercase leading-relaxed mb-4">{t.errorMultiPage}</p><button onClick={() => setStatus('idle')} className="w-full bg-slate-100 text-slate-500 font-black py-4 rounded-2xl uppercase tracking-widest text-[10px]">{t.restart}</button></div>}
    </div>
  );
};

