// Dynamic import for pdfjs
const PDFJS_CDN = "https://cdn.jsdelivr.net/npm/pdfjs-dist@4.4.168/build/pdf.min.mjs";

const PERSISTENCE_KEY = 'mahadbt_assist_state_v4';

// Helper to aggressively compress PDF bytes
async function compressPDFBytes(arrayBuffer: ArrayBuffer, t: any): Promise<Uint8Array | null> {
  try {
    const pdfjs = await import(PDFJS_CDN);
    pdfjs.GlobalWorkerOptions.workerSrc = `https://cdn.jsdelivr.net/npm/pdfjs-dist@${pdfjs.version}/build/pdf.worker.min.mjs`;

    const pdfDoc = await PDFLib.PDFDocument.load(arrayBuffer);
    pdfDoc.setTitle('');
    pdfDoc.setAuthor('');
    pdfDoc.setSubject('');
    pdfDoc.setCreator('');
    pdfDoc.setProducer('');

    const limit = 230 * 1024;
    let finalBytes = await pdfDoc.save();
    const totalPages = pdfDoc.getPageCount();

    // If it's already under limit, we are good
    if (finalBytes.length <= limit) return finalBytes;

    const dpiLevels = [150, 120, 100, 96, 90, 72, 60];
    const qualityLevels = [0.7, 0.6, 0.5, 0.4, 0.3, 0.2, 0.1];

    const loadingTask = pdfjs.getDocument({ data: arrayBuffer });
    const doc = await loadingTask.promise;

    let smallestBytes = finalBytes;

    for (let d = 0; d < dpiLevels.length; d++) {
      for (let q = 0; q < qualityLevels.length; q++) {
        const targetDPI = dpiLevels[d];
        const targetQuality = qualityLevels[q];

        const newPdf = await PDFLib.PDFDocument.create();
        for (let i = 1; i <= totalPages; i++) {
          const page = await doc.getPage(i);
          const viewport = page.getViewport({ scale: targetDPI / 72 });
          const canvas = document.createElement('canvas');
          const context = canvas.getContext('2d', { alpha: false })!;
          canvas.width = viewport.width;
          canvas.height = viewport.height;
          context.fillStyle = '#FFFFFF';
          context.fillRect(0, 0, canvas.width, canvas.height);
          await page.render({ canvasContext: context, viewport }).promise;
          const imgData = canvas.toDataURL('image/jpeg', targetQuality);
          const pdfImage = await newPdf.embedJpg(imgData);
          const newPage = newPdf.addPage([viewport.width, viewport.height]);
          newPage.drawImage(pdfImage, { x: 0, y: 0, width: viewport.width, height: viewport.height });
        }
        finalBytes = await newPdf.save();
        if (finalBytes.length < smallestBytes.length) {
          smallestBytes = finalBytes;
        }

        if (smallestBytes.length <= limit) return smallestBytes;

        // If ≤ 5 pages, we must exhaust all options to get it under limit
        if (totalPages <= 5) continue;
      }
    }

    // After exhausting all options:
    // If it's ≤ 5 pages, we return the smallest version we found (Success Guarantee)
    if (totalPages <= 5) return smallestBytes;

    // If it's > 5 pages and still over limit, return null to show failure
    return smallestBytes.length <= limit ? smallestBytes : null;
  } catch (e) {
    console.error(e);
    return null;
  }
}

