const SuccessUI: React.FC<{ bytes: Uint8Array, t: any, onRestart: () => void }> = ({ bytes, t, onRestart }) => {
  const [newName, setNewName] = useState('');
  const sizeKB = Math.round(bytes.length / 1024);

  const suggestions = [
    { label: 'Income_Certificate', val: 'Income_Certificate' },
    { label: 'Marksheet', val: 'Marksheet' },
    { label: 'Aadhaar_Card', val: 'Aadhaar_Card' },
    { label: 'Declaration', val: 'Declaration' },
    { label: 'Hostel_Bond_Tax_Receipt', val: 'Hostel_Bond_Tax_Receipt' },
  ];

  const downloadFile = () => {
    if (!newName.trim()) return;
    const blob = new Blob([bytes], { type: 'application/pdf' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    const cleanName = newName.trim().replace(/\.pdf$/i, '');
    a.download = `${cleanName}.pdf`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="bg-emerald-50 border border-emerald-100 rounded-3xl p-8 text-center space-y-6">
      <div className="bg-white w-14 h-14 rounded-full shadow-lg shadow-emerald-200 border border-emerald-100 flex items-center justify-center mx-auto text-emerald-600">
