      <div className="space-y-12 no-print">
        {declarationForms && <section className="space-y-5 text-left"><p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] px-2">Declaration Documents</p><div className="space-y-3">{declarationForms.map((decl, idx) => (<DeclarationCard key={idx} {...decl} />))}</div></section>}
        <section className="space-y-5 text-left"><p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] px-2">{t.academicDocs}</p><div className="space-y-3">{academicDocs.map((doc, idx) => (<div key={idx} className="bg-white border border-slate-100 p-4 rounded-2xl shadow-[0_2px_8px_rgba(0,0,0,0.02)] hover:border-blue-100 transition-colors group flex items-start justify-between min-w-0"><h4 className="font-black text-slate-700 text-[12px] leading-relaxed group-hover:text-blue-900 transition-colors uppercase tracking-tight pr-2 pt-0.5 whitespace-normal break-words flex-grow flex items-center">{doc.name}{doc.badge && <DocBadge type={doc.badge} />}</h4></div>))}</div></section>
        <section className="space-y-5 text-left"><p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] px-2">{t.categoryDocs}</p><div className="space-y-3">{govtDocs.map((doc, idx) => (
          <div key={idx} className="bg-white border border-slate-100 p-4 rounded-2xl shadow-[0_2px_8px_rgba(0,0,0,0.02)] hover:border-blue-100 transition-colors group flex items-start justify-between min-w-0">
            <h4 className="font-black text-slate-700 text-[12px] leading-relaxed group-hover:text-blue-900 transition-colors uppercase tracking-tight pr-2 pt-0.5 whitespace-normal break-words flex-grow flex items-center">{doc.name}{doc.badge && <DocBadge type={doc.badge} />}</h4>
          </div>
        ))}{choiceDocs && <div className="bg-slate-50/50 rounded-[2rem] p-6 border border-slate-100 space-y-4 mt-4"><div className="flex flex-col space-y-1"><span className="text-[9px] font-black text-emerald-700 uppercase tracking-tight">ANY ONE REQUIRED</span></div><div className="space-y-2">{choiceDocs.map((name, idx) => (<div key={idx} className="bg-white border border-slate-100 p-4 rounded-2xl shadow-sm flex items-start justify-between group min-w-0"><h4 className="font-black text-slate-800 text-[12px] leading-relaxed uppercase tracking-tight pr-2 pt-0.5 whitespace-normal break-words flex-grow flex items-center">{name}<DocBadge type="anyone" /></h4></div>))}</div></div>}</div></section>
        {hostelDocsList.length > 0 && <section className="space-y-5 text-left"><p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] px-2">{t.hostelDocs}</p><div className="space-y-3">{hostelDocsList.map((doc, idx) => (<div key={idx} className="bg-white border border-slate-100 p-4 rounded-2xl shadow-[0_2px_8px_rgba(0,0,0,0.02)] hover:border-blue-100 transition-colors group flex items-start justify-between min-w-0"><h4 className="font-black text-slate-700 text-[12px] leading-relaxed group-hover:text-blue-900 transition-colors uppercase tracking-tight pr-2 pt-0.5 whitespace-normal break-words flex-grow flex items-center">{doc.name}{doc.badge && <DocBadge type={doc.badge} />}</h4></div>))}</div></section>}
      </div>

      <section className="space-y-6 pt-10 border-t border-slate-100 no-print text-left">
        <h3 className="font-black text-slate-900 text-lg uppercase tracking-tight">{t.docToolsTitle}</h3>
        <div className="grid grid-cols-1 gap-3">
          {[ { label: t.btnMerge, sub: t.helperMerge, onClick: () => onOpenTool('merge') }, { label: t.btnCompress, sub: t.helperCompress, onClick: () => onOpenTool('compress') }, { label: t.btnImgToPdf, sub: t.helperImgToPdf, onClick: () => onOpenTool('img2pdf') } ].map((tool, i) => (
            <button key={i} onClick={tool.onClick} className="p-5 rounded-2xl border border-slate-100 hover:border-blue-300 hover:bg-white bg-white shadow-[0_2px_10px_rgba(0,0,0,0.02)] active:scale-[0.98] transition-all flex flex-col group text-left">
              <span className="font-black text-[11px] uppercase tracking-widest text-slate-800 group-hover:text-blue-900 transition-colors">{tool.label}</span>
              <span className="text-[9px] font-bold text-slate-400 mt-2 group-hover:text-slate-500 transition-colors">{tool.sub}</span>
