    docs.push({ name: '10th Marksheet' });
    docs.push({ name: '12th Marksheet' });
    if (!isASC) docs.push({ name: t.docAllotment });
    if (isFresh) {
      if (isMaster) { docs.push({ name: t.docGradMarksheet }); docs.push({ name: t.docGradTC }); } 
