          <h2 className="text-2xl font-black text-slate-900 tracking-tight leading-tight uppercase max-w-sm">{t.docsTitle}</h2>
          <div className="flex flex-col items-start sm:items-end shrink-0">
            <button 
              ref={printBtnRef}
